{"code": "import json

# Access the articles data
articles_data = locals()['var_functions.query_db:48']

# Load data from file if it's a path
if isinstance(articles_data, str):
    with open(articles_data, 'r') as f:
        articles = json.load(f)
else:
    articles = articles_data

# Check if there are sports articles with common sports terms
common_terms = ["nba", "nfl", "mlb", "nhl", "olympics", "olympic", "football", "basketball", "soccer", "baseball"]

print("Searching for sports keywords in all articles...")
all_matches = []

for article in articles:
    title_lower = article.get("title", "").lower()
    desc_lower = article.get("description", "").lower()

    for term in common_terms:
        if term in title_lower or term in desc_lower:
            all_matches.append({
                "term": term,
                "title": article.get("title"),
                "description": article.get("description"),
                "desc_len": len(article.get("description", ""))
            })
            break

print(f"Found {len(all_matches)} articles with common sports terms")

# Show top matches by description length
if all_matches:
    sorted_matches = sorted(all_matches, key=lambda x: x["desc_len"], reverse=True)
    print("\nTop 10 longest articles with sports terms:")
    for i, match in enumerate(sorted_matches[:10]):
        print(f"{i+1}. Term: {match['term']}, Length: {match['desc_len']}, Title: {match['title'][:80]}")
        print(f"   Desc: {match['description'][:100]}...")
        print()

result = json.dumps({
    "total_matches": len(all_matches),
    "top_match": all_matches[0] if all_matches else None
})
print("__RESULT__:")
print(result)"}
